-- Per operator (2026-06-05): import the Canada Shipping, US Shipping, and
-- Personal Delivery tabs of LILA customer fulfillment-20260605.xlsx into
-- public.fulfillment_log with full data (tracking, carrier, dates, prices,
-- update_status). The prior June 3 import only captured customer_name +
-- serial_number on most rows.
--
-- Three actions:
--   1. Expand fulfillment_queue.carrier CHECK to allow Canpar + GLS — the
--      Excel uses both for some Canadian + US shipments. Old constraint
--      only allowed UPS/FedEx/Purolator/Canada Post which blocked the
--      queue-cleanup UPDATE below.
--   2. Delete existing Canada/US/Personal Delivery rows in fulfillment_log
--      and re-insert from the 2026-06-05 Excel snapshot. Replacement tab
--      was handled in migration 20260605100000.
--   3. For each fulfillment_queue row whose order has a matching shipped
--      fulfillment_log row (customer name match, tracking number present),
--      mark it fulfilled (step=6, fulfilled_at) and backfill its serial /
--      tracking / carrier from the log. Lets Raymond see the actual
--      remaining queue without these already-shipped orders cluttering it.

alter table public.fulfillment_queue drop constraint if exists fulfillment_queue_carrier_check;
alter table public.fulfillment_queue add constraint fulfillment_queue_carrier_check
  check (carrier is null or carrier = any (array['UPS','FedEx','Purolator','Canada Post','Canpar','GLS']));

delete from public.fulfillment_log where source_tab in ('Canada Shipping','US Shipping','Personal Delivery');

-- Queue cleanup: mark fulfilled where an Excel shipped row matches by
-- customer name (exact or first+last token, case-insensitive). 53 rows
-- updated on 2026-06-05; idempotent (only touches fulfilled_at IS NULL).
update public.fulfillment_queue fq
set fulfilled_at      = coalesce(fq.fulfilled_at, fl.shipping_date::timestamptz, now()),
    step              = greatest(fq.step, 6),
    assigned_serial   = coalesce(fq.assigned_serial, fl.serial_number),
    tracking_num      = coalesce(fq.tracking_num, fl.tracking_number),
    carrier           = coalesce(fq.carrier, fl.carrier)
from public.orders o,
     public.fulfillment_log fl
where fq.order_id = o.id
  and fq.fulfilled_at is null
  and fl.tracking_number is not null
  and (
    lower(fl.customer_name) = lower(o.customer_name)
    or (
      split_part(lower(o.customer_name), ' ', 1) = split_part(lower(fl.customer_name), ' ', 1)
      and split_part(lower(o.customer_name), ' ', array_length(string_to_array(o.customer_name, ' '), 1))
        = split_part(lower(fl.customer_name), ' ', array_length(string_to_array(fl.customer_name, ' '), 1))
    )
  );
